   686|  const snapshot = await readSnapshot(snapshotId);
   687|  if (!snapshot) {
   688|    return {
   689|      snapshotId,
   690|      ok: false,
   691|      tablesRestored: 0,
   692|      totalRowsRestored: 0,
   693|      tables: [],
   694|      durationMs: Date.now() - startedAt,
   695|      timestamp,
   696|      requiresOwnerApproval: true,
   697|    };
   698|  }
