  error: string | null;
}> {
  const supa = resolveSupabase();
  if (supa.missing.length > 0) {
    return { bucket, objects: [], totalObjects: 0, totalBytes: 0, error: `not_configured: ${supa.missing.join(', ')}` };
  }

  try {
